import { Link } from "react-router-dom";

export default function ForgotUsername() {
  return (
    <div className="page">
      <div className="page-header">
        <h1>Forgot Username</h1>
        <p>Contact support with your registered email to recover your username.</p>
      </div>
      <div className="card">
        <p>Please use a real email that you used during signup.</p>
        <Link to="/login">Back to Sign In</Link>
      </div>
    </div>
  );
}
